@Slf4j
@Service
@RequiredArgsConstructor
public class DevicePermissionServiceImpl implements DevicePermissionService {
    private final DevicePermissionPersistence devicePermissionPersistence;
    private final UserPersistence userPersistence;

    @Override
    @Transactional(rollbackFor = Exception.class)
    public DevicePermissionData registerDevicePermission(Integer userId, DevicePermissionData incoming) {
        ensureUserExists(userId);
        return devicePermissionPersistence
            .findByUserIdAndFingerprint(userId, incoming.getFingerprint())
            .map(existing -> updateExistingPermission(existing, incoming))
            .orElseGet(() -> devicePermissionPersistence.save(incoming));
    }

    private DevicePermissionData updateExistingPermission(DevicePermissionData existing,
                                                           DevicePermissionData incoming) {
        existing.setPermissionStatus(incoming.getPermissionStatus());
        existing.setPermissionType(incoming.getPermissionType());
        return devicePermissionPersistence.save(existing);
    }

    private void ensureUserExists(Integer userId) {
        if (isUserMissing(userId)) {
            throw userNotFoundException(userId);
        }
    }

    private boolean isUserMissing(Integer userId) {
        return !userPersistence.existsById(userId);
    }

    private BusinessException userNotFoundException(Integer userId) {
        return new BusinessException(ErrorCode.USER_NOT_FOUND, userId.toString());
    }
}
