@Slf4j
@Service
@RequiredArgsConstructor
public class CountryServiceImpl implements CountryService {
    private final CountryPersistence countryPersistence;
    private final RedisTemplate<String, Object> redisTemplate;

    @Override
    public List<CountryData> getAllCountries() {
        String key = "countries::all";
        List<CountryData> cached = (List<CountryData>) redisTemplate.opsForValue().get(key);
        if (cached != null) {
            return cached;
        }
        List<CountryData> countries = countryPersistence.findAllActive();
        redisTemplate.opsForValue().set(key, countries);
        return countries;
    }

    @Cacheable(value = "countryData", key = "#countryCode")
    public CountryData getCountryByCode(String countryCode) {
        return countryPersistence.findByCode(countryCode).orElse(null);
    }
}
